import React from 'react';
import { BrowserRouter as Router, Route, Routes, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './contexts/AuthContext';
import LoginForm from './components/LoginForm';
import UserDashboard from './components/UserDashboard';
import MainRedactorDashboard from './components/MainRedactorDashboard';
import EngineerDashboard from './components/EngineerDashboard';

const PrivateRoute = ({ element, ...rest }) => {
  const { isAuthenticated } = useAuth();
  return isAuthenticated ? element : <Navigate to="/login" />;
};

const ProtectedRoute = ({ children }) => {
  const { user } = useAuth();

  if (!user) {
    return <Navigate to="/login" />;
  }

  if (user.role === 'user') {
    return <Navigate to="/user-dashboard" />;
  } else if (user.role === 'main_redactor') {
    return <Navigate to="/main-redactor-dashboard" />;
  } else if (user.role === 'engineer') {
    return <Navigate to="/engineer-dashboard" />;
  }

  return children;
};

const App = () => {
  return (
    <AuthProvider>
      <Router>
        <Routes>
          <Route path="/login" element={<LoginForm />} />
          <Route
            path="/dashboard"
            element={
              <PrivateRoute element={<UserDashboard />} />
            }
          />
          <Route
            path="/main-redactor-dashboard"
            element={
              <PrivateRoute element={<MainRedactorDashboard />} />
            }
          />
          <Route
            path="/engineer-dashboard"
            element={
              <PrivateRoute element={<EngineerDashboard />} />
            }
          />
          <Route path="*" element={<Navigate to="/login" />} />
        </Routes>
      </Router>
    </AuthProvider>
  );
};

export default App;
